blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie dowiesz się <strong>kolejności słów w pytaniach i sprzeciwach</strong>: użycia czasowników posiłkowych, struktury pytań Wh i typowych błędów.",
    "rules": [
        {
            "label": "Pytania tak/nie",
            "color": "emerald",
            "text": "<strong>Do/Does/Did + Temat + Czasownik</strong> — podstawowa struktura pytania:",
            "example": "Czy lubisz pizzę?"
        },
        {
            "label": "Jakie pytanie",
            "color": "blue",
            "text": "<strong>Jakie-słowo + Pomocnicze + Temat + Czasownik</strong> — pytanie z gdzie, co, dlaczego:",
            "example": "Gdzie ty żyć?"
        },
        {
            "label": "Zaprzeczenie",
            "color": "amber",
            "text": "<strong>Podmiot + Podmiot + Nie + Czasownik</strong> - struktura zaprzeczenia:",
            "example": "Nie lubię jabłek."
        }
    ]
}

{
    "title": "1. Czasowniki pomocnicze",
    "intro": "Do konstruowania pytań i zastrzeżeń potrzebne są czasowniki pomocnicze:",
    "items": [
        {
            "label": "Do",
            "title": "Ja / Ty / My / Oni",
            "subtitle": "Czy lubisz kawę? Nie wiem."
        },
        {
            "label": "Czy",
            "title": "On/ona/ono",
            "subtitle": "Czy ona pracuje? On nie gra."
        },
        {
            "label": "Czy",
            "title": "Czas przeszły",
            "subtitle": "Czy oni przyszli? Nie widzieliśmy."
        }
    ]
}

{
    "title": "2. Pytania typu „tak/nie”",
    "sections": [
        {
            "label": "Czasowniki regularne",
            "color": "emerald",
            "description": "W przypadku czasowników regularnych użyj <strong>do/does/did</strong> przed podmiotem.",
            "examples": [
                {
                    "en": "Czy lubisz pizzę?",
                    "ua": "Lubisz pizza?"
                },
                {
                    "en": "Czy ona gra w tenisa?",
                    "ua": "Czy ona gra w tenisa?"
                },
                {
                    "en": "Czy oglądają program? gotowy?",
                    "ua": "Вони дивились шоу?"
                }
            ]
        },
        {
            "label": "To be та модальні дієслова",
            "color": "sky",
            "description": "Для <strong>to be</strong> та модальних дієслів просто міняй місцями підмет і дієслово — do/does/did не потрібні.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Czy jesteś gotowy?"
                },
                {
                    "en": "Czy on nadchodzi?",
                    "ua": "On idzie?"
                },
                {
                    "en": "Umiesz pływać?",
                    "ua": "Umiesz pływać? skończyłeś?"
                },
                {
                    "en": "Have you finished?",
                    "ua": "Ти закінчив?"
                }
            ]
        }
    ]
}

{
    "title": "3. Pytania typu „Wh” ",
    "sections": [
        {
            "label": "Struktura pytania „Wh” ",
            "color": "emerald",
            "description": "<strong>Słowo „Wh” + podmiot + czasownik + podmiot</strong> — na początku słowo pytające, potem czasownik pomocniczy.",
            "examples": [
                {
                    "en": "Gdzie mieszkasz?",
                    "ua": "Gdzie mieszkasz? żyje?"
                },
                {
                    "en": "Co ona jadła?",
                    "ua": "Co jadła?"
                },
                {
                    "en": "Dlaczego biegają?",
                    "ua": "Dlaczego biegają?"
                },
                {
                    "en": "Jak mogę pomóc?",
                    "ua": " pomóc?"
                }
            ]
        },
        {
            "label": "Jakie słowo jako temat",
            "color": "amber",
            "description": "Jeśli podmiotem jest <strong>Kto</strong> lub <strong>Co</strong>, czasownik pomocniczy <strong>nie jest potrzebny</strong>.",
            "examples": [
                {
                    "en": "Kto do Ciebie dzwonił?",
                    "ua": "Kto do Ciebie dzwonił? dzwonił?"
                },
                {
                    "en": "Co się stało?",
                    "ua": "Co się stało?"
                },
                {
                    "en": "Kto tu mieszka?",
                    "ua": "Kto tu mieszka?"
                }
            ],
            "note": "Porównaj: <strong>Kto do Ciebie dzwonił?</strong> (kto jest tematem) vs <strong>Do kogo dzwoniłeś?</strong> (ty jesteś tematem)."
        }
    ]
}

{
    "title": "4. Przeczenia",
    "sections": [
        {
            "label": "Czasowniki regularne",
            "color": "emerald",
            "description": "Dodaj <strong>do/does/did + not</strong> przed głównym czasownikiem.",
            "examples": [
                {
                    "en": "Nie lubię (nie) jabłek.",
                    "ua": "Nie lubię jabłek."
                },
                {
                    "en": "Ona się nie (nie) bawi piłka nożna.",
                    "ua": "Ona nie gra (nie) gra w piłkę nożną."
                },
                {
                    "en": "Nie widzieli (nie) filmu.",
                    "ua": "Nie widzieli filmu."
                }
            ]
        },
        {
            "label": "Być i czasowniki modalne",
            "color": "sky",
            "description": "Dodaj <strong>nie</strong> bezpośrednio po być lub czasowniku modalnym.",
            "examples": [
                {
                    "en": "On nie jest (nie) gotowy.",
                    "ua": "Nie jest gotowy."
                },
                {
                    "en": "Nie było (nie było) tam.",
                    "ua": "Nie było tam."
                },
                {
                    "en": "Nie wolno (nie wolno) tego dotykać.",
                    "ua": "Nie wolno (nie wolno) tego dotykać."
                },
                {
                    "en": "Nie mogą (nie mogą) przyjść.",
                    "ua": "Nie mogą przyjść."
                }
            ]
        }
    ]
}

{
    "title": "5. Skurcze",
    "intro": "W mowie potocznej słowo not jest często skracane:",
    "rows": [
        {
            "en": "nie",
            "ua": "nie",
            "note": "nie wiem."
        },
        {
            "en": "tak nie",
            "ua": "nie",
            "note": "nie podoba jej się to."
        },
        {
            "en": "nie",
            "ua": "nie",
            "note": "Nie poszliśmy."
        },
        {
            "en": "jest nie",
            "ua": "nie",
            "note": "nie ma go tutaj."
        },
        {
            "en": "nie",
            "ua": "nie",
            "note": "nie przyjdą."
        },
        {
            "en": "będzie nie",
            "ua": "nie",
            "note": "nie zapomnę."
        },
        {
            "en": "nie może",
            "ua": "nie może",
            "note": "ona nie umie pływać.[[[CODX_40]]]📌 W formalnym piśmie: korzystaj z pełnych formularzy."
        }
    ],
    "warning": "📌 У формальному письмі використовуй повні форми."
}

{
    "title": "6. Typowe błędy osób mówiących po ukraińsku",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "W pytaniu nie ma czasownika pomocniczego.",
            "wrong": "Lubisz pizzę?",
            "right": " ✅ <span class="font-mono">Czy lubisz pizzę?</span>[[[CODX_4]]]Błąd 2"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Brak czasownika pomocniczego w pytaniu Wh.",
            "wrong": "Gdzie mieszkasz?",
            "right": "​​​​ <span class="font-mono">Gdzie mieszkasz?</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Zły wybór rzeczy do zrobienia.",
            "wrong": "Nie lubi tego.",
            "right": "​​​​​​​​​ jabłka.</span>[[CODX_SEG_16]]]7. Krótkie streszczenie"
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Заперечення без допоміжного дієслова.",
            "wrong": "I no like apples.",
            "right": "✅ <span class="font-mono">I don't like apples.</span>"
        }
    ]
}

{
    "title": "8. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą opcję",
    "select_intro": "Wybierz zdania w odpowiedniej kolejności.",
    "selects": [
        {
            "label": "a) Czy lubisz kawę? / b) Lubisz kawę?",
            "prompt": "Która opcja jest poprawna?"
        },
        {
            "label": "a) Gdzie ona mieszka? / b) Gdzie ona mieszka?",
            "prompt": "Która opcja jest prawidłowa?"
        },
        {
            "label": "a) On tu nie pracuje. / b) On tu nie działa.",
            "prompt": "Która opcja jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b"
    ],
    "input_title": "Ćwiczenie 2. Skonstruuj pytanie",
    "input_intro": "Zamień stwierdzenie na pytanie.",
    "inputs": [
        {
            "before": " Mówisz po angielsku.",
            "after": " → Czy...?"
        },
        {
            "before": "Ona pracuje w banku.",
            "after": " → Czy ona...?"
        },
        {
            "before": "Poszli na imprezę.",
            "after": " → Czy oni...?"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Zbuduj negację",
    "rephrase_intro": "Zamień stwierdzenie na negację.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Lubię jabłka.",
            "example_target": "Nie lubię jabłka."
        },
        {
            "original": "1. Ona gra w tenisa.",
            "placeholder": "Napisz sprzeciw"
        },
        {
            "original": "2. Oglądają film. Przysłówki i okoliczności",
            "placeholder": "Напиши заперечення"
        }
    ]
}

{
    "title": "Інші сторінки з базової граматики",
    "items": [
        {
            "label": "Basic Word Order — Порядок слів у ствердженні",
            "current": false
        },
        {
            "label": "Word Order in Questions and Negatives — Питання та заперечення",
            "current": true
        },
        {
            "label": "Word Order with Adverbs — Прислівники та обставини",
            "current": false
        }
    ]
}
